var IOS_PARSERS = {
  "show ip interface brief": function(output) {
    var lines = output.split("\n");
    var interfaces = [];
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      var match = line.match(/^(\S+)\s+(\S+)\s+(\S+)\s+(\S+)\s+(\S+)\s+(\S+)$/);
      if (match && !match[1].startsWith("Interface")) {
        interfaces.push({
          interface: match[1],
          ipAddress: match[2],
          ok: match[3],
          method: match[4],
          status: match[5],
          protocol: match[6]
        });
      }
    }
    return { raw: output, interfaces: interfaces };
  },
  
  "show vlan brief": function(output) {
    var lines = output.split("\n");
    var vlans = [];
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      var match = line.match(/^(\d+)\s+(\S+)\s+(\S+)\s*(.*?)$/);
      if (match) {
        var ports = match[4] ? match[4].split(",").map(function(p) { return p.trim(); }).filter(function(p) { return p; }) : [];
        vlans.push({
          id: parseInt(match[1]),
          name: match[2],
          status: match[3],
          ports: ports
        });
      }
    }
    return { raw: output, vlans: vlans };
  },
  
  "show vlan": function(output) {
    return IOS_PARSERS["show vlan brief"](output);
  },
  
  "show ip route": function(output) {
    var lines = output.split("\n");
    var routes = [];
    var gatewayOfLastResort = null;
    
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      
      var gwMatch = line.match(/Gateway of last resort is (.+)/i);
      if (gwMatch) {
        gatewayOfLastResort = gwMatch[1];
        continue;
      }
      
      var routeMatch = line.match(/^([CLSORDBEIUM\*])\s+(\S+)\s+(?:is\s+)?(.+)$/);
      if (routeMatch) {
        var typeCode = routeMatch[1];
        var network = routeMatch[2];
        var rest = routeMatch[3];
        
        var route = {
          type: typeCode,
          network: network,
          nextHop: null,
          interface: null
        };
        
        if (rest.indexOf("directly connected") >= 0) {
          var ifaceMatch = rest.match(/connected,?\s*(\S+)/);
          if (ifaceMatch) route.interface = ifaceMatch[1];
        } else if (rest.indexOf("via") >= 0) {
          var viaMatch = rest.match(/via\s+(\S+)/);
          if (viaMatch) route.nextHop = viaMatch[1].replace(",", "");
        }
        
        routes.push(route);
      }
    }
    
    return { raw: output, routes: routes, gatewayOfLastResort: gatewayOfLastResort };
  },
  
  "show running-config": function(output) {
    var sections = {};
    var currentSection = null;
    var currentContent = [];
    var hostname = null;
    var interfaces = {};
    var lines = output.split("\n");
    
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i];
      
      if (line.indexOf("hostname ") === 0) {
        hostname = line.substring(9).trim();
      }
      
      if (line.indexOf("!") === 0) {
        if (currentSection) {
          sections[currentSection] = currentContent.join("\n");
        }
        currentSection = null;
        currentContent = [];
      } else if (line.indexOf("interface ") === 0) {
        currentSection = line.trim();
        currentContent = [line];
        interfaces[line.substring(10).trim()] = "";
      } else if (line.indexOf("vlan ") === 0 || line.indexOf("router ") === 0) {
        currentSection = line.trim();
        currentContent = [line];
      } else if (currentSection) {
        currentContent.push(line);
      }
    }
    
    return { raw: output, hostname: hostname, sections: sections, interfaces: interfaces };
  },
  
  "show interfaces": function(output) {
    var interfaces = [];
    var current = null;
    var lines = output.split("\n");
    
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i];
      
      var ifaceMatch = line.match(/^(\S+)\s+is\s+(\S+),\s+line protocol is (\S+)/);
      if (ifaceMatch) {
        if (current) interfaces.push(current);
        current = {
          name: ifaceMatch[1],
          status: ifaceMatch[2],
          protocol: ifaceMatch[3]
        };
      }
      
      if (current) {
        if (line.indexOf("  Hardware is ") === 0) {
          current.hardware = line.substring(14).trim();
        }
        if (line.indexOf("  Description: ") === 0) {
          current.description = line.substring(15).trim();
        }
        if (line.indexOf("  Internet address is ") === 0) {
          var ipMatch = line.match(/Internet address is (\S+)/);
          if (ipMatch) {
            var parts = ipMatch[1].split("/");
            current.ipAddress = parts[0];
            if (parts[1]) current.cidr = parseInt(parts[1]);
          }
        }
      }
    }
    
    if (current) interfaces.push(current);
    return { raw: output, interfaces: interfaces };
  },
  
  "show ip arp": function(output) {
    var entries = [];
    var lines = output.split("\n");
    
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      var match = line.match(/^(Internet)\s+(\S+)\s+(\S+)\s+(\S+)\s+(\S+)\s+(\S+)$/i);
      if (match) {
        entries.push({
          protocol: match[1],
          address: match[2],
          age: match[3],
          mac: match[4],
          type: match[5],
          interface: match[6]
        });
      }
    }
    
    return { raw: output, entries: entries };
  },
  
  "show mac address-table": function(output) {
    var entries = [];
    var lines = output.split("\n");
    
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      var match = line.match(/^(\S+)\s+([0-9a-fA-F.]+)\s+(\S+)\s+(\S+)$/);
      if (match) {
        entries.push({
          vlan: match[1],
          macAddress: match[2],
          type: match[3].toLowerCase(),
          ports: [match[4]]
        });
      }
    }
    
    return { raw: output, entries: entries };
  },
  
  "show spanning-tree": function(output) {
    var vlans = [];
    var current = null;
    var lines = output.split("\n");
    
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i];
      
      var vlanMatch = line.match(/^VLAN(\d+)/);
      if (vlanMatch) {
        if (current) vlans.push(current);
        current = { vlan: parseInt(vlanMatch[1]), interfaces: [] };
      }
      
      if (current) {
        if (line.indexOf("  Root ID") === 0) {
          current.rootBridgeId = line.substring(10).trim();
          current.rootBridge = false;
        }
        if (line.indexOf("  Bridge ID") === 0) {
          current.bridgeId = line.substring(12).trim();
        }
        
        var ifaceMatch = line.match(/^\s+(\S+)\s+(\S+)\s+(\S+)\s+(\d+)\s+(\S+)/);
        if (ifaceMatch) {
          current.interfaces.push({
            port: ifaceMatch[1],
            role: ifaceMatch[2].toLowerCase(),
            state: ifaceMatch[3].toLowerCase(),
            cost: parseInt(ifaceMatch[4])
          });
        }
      }
    }
    
    if (current) vlans.push(current);
    return { raw: output, vlans: vlans };
  },
  
  "show version": function(output) {
    var result = { raw: output };
    var lines = output.split("\n");
    
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i];
      
      if (line.indexOf("Version ") >= 0) {
        var vMatch = line.match(/Version (\S+)/);
        if (vMatch) result.version = vMatch[1];
      }
      
      if (line.indexOf(" uptime is ") >= 0) {
        result.uptime = line.substring(line.indexOf(" uptime is ") + 11);
      }
      
      var uptimeMatch = line.match(/^(\S+)\s+uptime is /);
      if (uptimeMatch) {
        result.hostname = uptimeMatch[1];
      }
    }
    
    return result;
  },
  
  "show cdp neighbors": function(output) {
    var neighbors = [];
    var lines = output.split("\n");
    var started = false;
    
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      
      if (line.indexOf("Device ID") >= 0) {
        started = true;
        continue;
      }
      
      if (!started || !line) continue;
      
      var parts = line.split(/\s+/);
      if (parts.length >= 6) {
        neighbors.push({
          deviceId: parts[0],
          localInterface: parts[1],
          holdtime: parseInt(parts[2]),
          capability: parts[3],
          platform: parts[4],
          portId: parts[5]
        });
      }
    }
    
    return { raw: output, neighbors: neighbors };
  }
};

function getParser(command) {
  var cmd = command.toLowerCase().trim();
  
  if (IOS_PARSERS[cmd]) return IOS_PARSERS[cmd];
  
  for (var key in IOS_PARSERS) {
    if (cmd.indexOf(key.toLowerCase()) === 0) {
      return IOS_PARSERS[key];
    }
  }
  
  return null;
}

// ============================================================================
// Command Handlers
// ============================================================================

function handleAddDevice(payload) {
  var lw = getLW();
  var net = getNet();
  var model = resolveModel(payload.model);
  var name = payload.name || model;
  var x = payload.x !== undefined ? payload.x : 100;
  var y = payload.y !== undefined ? payload.y : 100;
  
  var typeList = payload.deviceType !== undefined 
    ? [payload.deviceType] 
    : getDeviceTypeCandidates(model);
  
  var created = createDeviceWithFallback(model, x, y, typeList, lw, net);
  if (!created) {
    return { ok: false, error: "Failed to add device for model: " + model };
  }
  
  var autoName = created.autoName;
  var device = created.device;
  
  device.setName(name);
  if (device.skipBoot) device.skipBoot();
  
  return { ok: true, name: name, autoName: autoName, model: model, deviceType: created.typeId };
}

function handleRemoveDevice(payload) {
  getLW().removeDevice(payload.name);
  return { ok: true, name: payload.name };
}

function handleListDevices() {
  var net = getNet();
  var count = net.getDeviceCount();
  var devices = [];
  
  for (var i = 0; i < count; i++) {
    var device = net.getDeviceAt(i);
    if (device) {
      devices.push({
        name: device.getName(),
        model: device.getModel(),
        type: device.getType(),
        power: device.getPower()
      });
    }
  }
  
  return { ok: true, devices: devices, count: count };
}

function handleRenameDevice(payload) {
  var device = getNet().getDevice(payload.oldName);
  if (!device) return { ok: false, error: "Device not found: " + payload.oldName };
  device.setName(payload.newName);
  return { ok: true, oldName: payload.oldName, newName: payload.newName };
}

function handleAddModule(payload) {
  var device = getNet().getDevice(payload.device);
  if (!device) return { ok: false, error: "Device not found: " + payload.device };
  
  if (!device.addModule) return { ok: false, error: "Device does not support modular expansion" };
  
  var wasPowered = device.getPower();
  
  if (wasPowered) device.setPower(false);
  
  var result = device.addModule(payload.slot, payload.module);
  
  if (wasPowered) {
    device.setPower(true);
    if (device.skipBoot) device.skipBoot();
  }
  
  if (!result) return { ok: false, error: "Failed to add module to slot " + payload.slot };
  
  return { ok: true, device: payload.device, slot: payload.slot, module: payload.module };
}

function handleRemoveModule(payload) {
  var device = getNet().getDevice(payload.device);
  if (!device) return { ok: false, error: "Device not found: " + payload.device };
  
  if (!device.removeModule) return { ok: false, error: "Device does not support modular expansion" };
  
  var wasPowered = device.getPower();
  
  if (wasPowered) device.setPower(false);
  
  var result = device.removeModule(payload.slot);
  
  if (wasPowered) {
    device.setPower(true);
    if (device.skipBoot) device.skipBoot();
  }
  
  if (!result) return { ok: false, error: "Failed to remove module from slot " + payload.slot };
  
  return { ok: true, device: payload.device, slot: payload.slot };
}

function handleAddLink(payload) {
  var lw = getLW();
  var cableType = CABLE_TYPES[payload.linkType] || CABLE_TYPES.auto;
  
  var success = lw.createLink(
    payload.device1, payload.port1,
    payload.device2, payload.port2,
    cableType
  );
  
  if (!success) return { ok: false, error: "Failed to create link" };
  
  return {
    ok: true,
    device1: payload.device1,
    port1: payload.port1,
    device2: payload.device2,
    port2: payload.port2,
    linkType: payload.linkType || "auto"
  };
}

function handleRemoveLink(payload) {
  getLW().deleteLink(payload.device, payload.port);
  return { ok: true };
}

function handleConfigHost(payload) {
  var device = getNet().getDevice(payload.device);
  if (!device) return { ok: false, error: "Device not found: " + payload.device };
  
  var port = device.getPortAt(0);
  if (!port) return { ok: false, error: "No ports on device" };
  
  if (payload.dhcp === true) {
    try { port.setDhcpEnabled(true); } catch(e) {}
  } else {
    if (payload.ip && payload.mask) {
      port.setIpSubnetMask(payload.ip, payload.mask);
    }
    if (payload.gateway) {
      port.setDefaultGateway(payload.gateway);
    }
    if (payload.dns) {
      port.setDnsServerIp(payload.dns);
    }
  }
  
  return { ok: true, device: payload.device, ip: payload.ip };
}

function handleConfigIos(payload) {
  var device = getNet().getDevice(payload.device);
  if (!device) return { ok: false, error: "Device not found: " + payload.device };
  
  if (device.skipBoot) device.skipBoot();
  
  var term = device.getCommandLine();
  if (!term) return { ok: false, error: "Device does not support CLI" };
  
  var results = [];
  for (var i = 0; i < payload.commands.length; i++) {
    var result = term.enterCommand(payload.commands[i]);
    results.push({ command: payload.commands[i], result: result });
  }
  
  if (payload.save !== false) {
    term.enterCommand("write memory");
  }
  
  return { ok: true, device: payload.device, executed: results.length };
}

function handleExecIos(payload) {
  var device = getNet().getDevice(payload.device);
  if (!device) return { ok: false, error: "Device not found: " + payload.device };
  
  var term = device.getCommandLine();
  if (!term) {
    return { ok: false, error: "Device does not support CLI" };
  }

  var response = term.enterCommand(payload.command);
  var status = response && response[0];
  var output = response && response[1] || "";
  
  var result = {
    ok: status === 0,
    raw: output,
    status: status
  };
  
  if (payload.parse !== false) {
    var parser = getParser(payload.command);
    if (parser) {
      try {
        result.parsed = parser(output);
      } catch (e) {
        result.parseError = String(e);
      }
    }
  }
  
  return result;
}

function handleSnapshot() {
  var net = getNet();
  var count = net.getDeviceCount();
  var devices = {};
  var links = {};
  
  for (var i = 0; i < count; i++) {
    var device = net.getDeviceAt(i);
    if (!device) continue;
    
    var name = device.getName();
    var portCount = device.getPortCount();
    var ports = [];
    
    for (var p = 0; p < portCount; p++) {
      try {
        var port = device.getPortAt(p);
        if (!port) continue;
        
        var portName = port.getName();
        var portInfo = { name: portName };
        
        try { portInfo.ipAddress = port.getIpAddress(); } catch(e) {}
        try { portInfo.subnetMask = port.getSubnetMask(); } catch(e) {}
        
        try {
          var link = port.getLink();
          if (link) {
            for (var j = 0; j < count; j++) {
              var otherDevice = net.getDeviceAt(j);
              if (!otherDevice || otherDevice.getName() === name) continue;
              
              var otherPortCount = otherDevice.getPortCount();
              for (var op = 0; op < otherPortCount; op++) {
                try {
                  var otherPort = otherDevice.getPortAt(op);
                  if (!otherPort) continue;
                  
                  var otherLink = otherPort.getLink();
                  if (otherLink && otherLink === link) {
                    var linkId = name + ":" + portName + "-" + otherDevice.getName() + ":" + otherPort.getName();
                    
                    var dev1, pt1, dev2, pt2;
                    if (name < otherDevice.getName()) {
                      dev1 = name; pt1 = portName;
                      dev2 = otherDevice.getName(); pt2 = otherPort.getName();
                    } else {
                      dev1 = otherDevice.getName(); pt1 = otherPort.getName();
                      dev2 = name; pt2 = portName;
                    }
                    
                    links[linkId] = {
                      id: linkId,
                      device1: dev1,
                      port1: pt1,
                      device2: dev2,
                      port2: pt2,
                      cableType: "auto"
                    };
                  }
                } catch(e) {}
              }
            }
          }
        } catch(e) {}
        
        ports.push(portInfo);
      } catch(e) {
        ports.push({ name: "port" + p });
      }
    }
    
    devices[name] = {
      name: name,
      model: device.getModel(),
      type: device.getType(),
      power: device.getPower(),
      ports: ports
    };
  }
  
  return {
    ok: true,
    version: "1.0",
    timestamp: Date.now(),
    devices: devices,
    links: links,
    metadata: { deviceCount: count, linkCount: Object.keys(links).length }
  };
}

function handleInspect(payload) {
  var device = getNet().getDevice(payload.device);
  if (!device) return { ok: false, error: "Device not found: " + payload.device };
  
  var portCount = device.getPortCount();
  var ports = [];
  
  for (var i = 0; i < portCount; i++) {
    try {
      var port = device.getPortAt(i);
      if (!port) continue;
      
      var portInfo = { name: port.getName() };
      try { portInfo.ipAddress = port.getIpAddress(); } catch(e) {}
      try { portInfo.subnetMask = port.getSubnetMask(); } catch(e) {}
      try { portInfo.macAddress = port.getMacAddress(); } catch(e) {}
      try { portInfo.defaultGateway = port.getDefaultGateway(); } catch(e) {}
      
      ports.push(portInfo);
    } catch(e) {}
  }
  
  var result = {
    ok: true,
    name: device.getName(),
    model: device.getModel(),
    type: device.getType(),
    power: device.getPower(),
    ports: ports
  };
  
  if (payload.includeXml && device.serializeToXml) {
    try { result.xml = device.serializeToXml(); } catch(e) {}
  }
  
  return result;
}

function handleHardwareInfo() {
  var factory = ipc.hardwareFactory();
  var keys = [];
  for (var key in factory) keys.push(key);
  return { ok: true, keys: keys };
}

function handleHardwareCatalog(payload) {
  var factory = ipc.hardwareFactory();
  var list = factory.devices || [];
  var limit = payload.limit || 50;
  var results = [];
  
  for (var i = 0; i < list.length && results.length < limit; i++) {
    var item = list[i];
    var entry = {};
    try { entry.name = item.name; } catch(e) {}
    try { entry.model = item.model; } catch(e) {}
    try { entry.displayName = item.displayName; } catch(e) {}
    try { entry.deviceType = item.deviceType; } catch(e) {}
    results.push(entry);
  }
  
  return { ok: true, items: results, total: list.length || 0 };
}

function handleCommandLog(payload) {
  var cl = ipc.commandLog();
  cl.setEnabled(true);
  
  var count = cl.getEntryCount();
  var limit = payload.limit || 100;
  var start = Math.max(0, count - limit);
  var entries = [];
  
  for (var i = start; i < count; i++) {
    var entry = cl.getEntryAt(i);
    entries.push({
      index: i,
      time: entry.getTimeToString ? entry.getTimeToString() : "",
      device: entry.getDeviceName ? entry.getDeviceName() : "",
      prompt: entry.getPrompt ? entry.getPrompt() : "",
      command: entry.getCommand ? entry.getCommand() : ""
    });
  }
  
  return { ok: true, entries: entries, count: count };
}

// ============================================================================
// Command Dispatcher
// ============================================================================

return (function(payload, ipc, dprint) {
  try {
    dprint("[Runtime] Processing: " + payload.type);
    
    switch (payload.type) {
      case "addDevice": return handleAddDevice(payload);
      case "removeDevice": return handleRemoveDevice(payload);
      case "listDevices": return handleListDevices(payload);
      case "renameDevice": return handleRenameDevice(payload);
      case "addModule": return handleAddModule(payload);
      case "removeModule": return handleRemoveModule(payload);
      case "addLink": return handleAddLink(payload);
      case "removeLink": return handleRemoveLink(payload);
      case "configHost": return handleConfigHost(payload);
      case "configIos": return handleConfigIos(payload);
      case "execIos": return handleExecIos(payload);
      case "snapshot": return handleSnapshot();
      case "inspect": return handleInspect(payload);
      case "hardwareInfo": return handleHardwareInfo();
      case "hardwareCatalog": return handleHardwareCatalog(payload);
      case "commandLog": return handleCommandLog(payload);
      default: return { ok: false, error: "Unknown command: " + payload.type };
    }
  } catch (e) {
    dprint("[Runtime] Error: " + String(e));
    return { ok: false, error: String(e), stack: String(e.stack || "") };
  }
})(payload, ipc, dprint);
